async function synthesizeSummaries(
    partialSummaries: string[], 
    userPrompt: string, 
    filtersDescription: string,
    periodoAnalise: string
): Promise<string> {
    const synthesisPrompt = `
      Você é um analista de dados sênior. Sua tarefa é consolidar vários resumos parciais de uma análise de dados em um único relatório final coeso e abrangente.

      **Contexto da Análise Original:**
      - Pergunta do usuário: "${userPrompt}"
      - ${filtersDescription}
      - ${periodoAnalise}

      **Resumos Parciais (de diferentes partes da planilha):**
      ${partialSummaries.map((s, i) => `--- Resumo da Parte ${i + 1} ---\n${s}`).join('\n\n')}

      **Sua Tarefa:**
      1.  **Sintetize:** Leia todos os resumos parciais. Agregue os números, combine as listas e consolide os insights. Não apenas liste os resumos; crie um novo relatório unificado.
      2.  **Responda à Pergunta:** Certifique-se de que o relatório final responda diretamente à pergunta original do usuário, usando os dados agregados.
      3.  **Formatação Clara (CRÍTICO):** 
          - Use títulos em negrito (ex: **Métricas Gerais**) para separar seções.
          - Use listas de marcadores ('-') para CADA métrica ou dado individual.
          - **Regra de Ouro do Espaçamento:** Insira DUAS quebras de linha (\\n\\n) APÓS CADA item da lista e APÓS CADA seção. O texto deve ser muito arejado.
          - **Uma informação por linha:** Apresente CADA dado em sua própria linha isolada. Não agrupe múltiplos dados na mesma linha.
          - **Formato de Tempo:** Use estritamente 'hh:mm' para apresentar todas as horas e durações.
      4.  **Inclua o Contexto:** Comece o relatório final com a seção **Filtros Aplicados:** (se houver) e termine com a linha do período analisado.

      A resposta deve ser APENAS o texto do relatório final consolidado, em português do Brasil.
    `;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: synthesisPrompt,
            config: {
                systemInstruction: "Você é um assistente de análise de dados especialista em produção de TV. Você prioriza clareza visual, usando muitas quebras de linha e formato de hora hh:mm.",
                thinkingConfig: { thinkingBudget: 8192 },
            },
        });

        if (!response || typeof response.text !== 'string' || !response.text.trim()) {
            throw new Error(`A IA falhou ao consolidar os resultados.`);
        }
        return response.text.trim();
    } catch (error) {
        console.error("Error during synthesis:", error);
        throw new Error("Falha ao consolidar os resultados da análise com a IA.");
    }
}

export const analyzeSpreadsheetData = async (
    data: SheetRow[], 
    userPrompt: string, 
    filters: Filter[], 
    periodoAnalise: string,
    onProgress?: (progress: { current: number; total: number, step: 'analyze' | 'synthesize' }) => void
): Promise<AnalysisResultData> => {

    const filtersDescription = filters.length > 0
        ? `A análise foi pré-filtrada com os seguintes critérios: ${filters.map(f => {
            if (typeof f.value === 'object' && f.value !== null) {
                const { start, end } = f.value as { start?: string, end?: string };
                const formatDate = (dateStr: string | undefined) => dateStr ? new Date(dateStr + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: '2-digit' }) : '';
                return `${f.column} entre ${formatDate(start)} e ${formatDate(end)}`;
            }
            return `${f.column} = "${f.value}"`;
          }).join(', ')}.`
        : "A análise está sendo feita no conjunto de dados completo.";

    const analyzeChunk = async (chunkData: SheetRow[], isChunked: boolean, chunkInfo: string): Promise<AnalysisResultData> => {
        const prompt = `
      Você é um analista de dados sênior. Sua tarefa é analisar uma planilha com registros de gravações de estúdio e retornar um relatório numérico e dados para gráficos.

      **Colunas de Interesse Principal:**
      As colunas principais incluem 'equipe', 'programa', 'estudio', 'data', 'hora inicial', 'duracao_horas', 'tipo' (G, V ou C).

      **Instruções de Análise de Equipe:**
      - Se houver a coluna 'equipe', analise quais equipes são as mais produtivas (mais horas gravadas).
      - Identifique se alguma equipe específica tem um alto índice de cancelamentos.
      - Apresente totais acumulados por equipe se a pergunta do usuário for sobre faturamento ou horas trabalhadas.

      ${isChunked ? `**Contexto de Análise em Partes:**\nVocê está analisando uma parte (${chunkInfo}) de um conjunto de dados maior.\n` : ''}

      **Contexto da Análise:**
      ${filtersDescription}
      A planilha contém ${chunkData.length} linhas após a filtragem.
      ${periodoAnalise}

      **Regras de Validação:**
      - Se Tipo='C' (Cancelado), ignore valores em colunas '(res)'. Verifique se existem valores em colunas '(Rea)'.
      - Formato de Tempo: Use estritamente 'hh:mm'.

      Dados JSON:
      ${JSON.stringify(chunkData.map(row => {
          const { __originalRowIndex, ...rest } = row;
          return { ...rest, rowIndex: __originalRowIndex };
      }))}

      Pergunta do usuário:
      "${userPrompt}"

      **Gráficos Sugeridos (chartData):**
      - Se houver a coluna equipe, gere: 'Horas Totais por Equipe'.
      - Caso contrário, gere: 'Horas por Estúdio' e 'Distribuição por Tipo'.
    `;

      try {
          const response = await ai.models.generateContent({
              model: "gemini-2.5-flash",
              contents: prompt,
              config: {
                  systemInstruction: "Você é um especialista em TV. Suas respostas devem ser JSON. Você prioriza a análise de equipes e estúdios.",
                  responseMimeType: "application/json",
                  responseSchema: analysisResponseSchema,
                  thinkingConfig: { thinkingBudget: 8192 },
              },
          });

          if (!response || !response.text?.trim()) {
              throw new Error(`A IA não retornou uma resposta válida.`);
          }

          return JSON.parse(response.text.trim()) as AnalysisResultData;
      } catch (error: any) {
          throw new Error("Falha ao comunicar com o serviço de IA.");
      }
    };

    const CHUNK_SIZE = 1500;
    if (data.length <= CHUNK_SIZE) {
        onProgress?.({ current: 1, total: 1, step: 'analyze' });
        return await analyzeChunk(data, false, '');
    }

    const chunks: SheetRow[][] = [];
    for (let i = 0; i < data.length; i += CHUNK_SIZE) chunks.push(data.slice(i, i + CHUNK_SIZE));

    const partialSummaries: string[] = [];
    const allInvalidRows: InvalidRow[] = [];
    const allChartDataChunks: ChartData[][] = [];

    for (let i = 0; i < chunks.length; i++) {
        onProgress?.({ current: i + 1, total: chunks.length, step: 'analyze' });
        const result = await analyzeChunk(chunks[i], true, `Parte ${i+1}`);
        if (result.resumo) partialSummaries.push(result.resumo);
        if (result.dadosInvalidos) allInvalidRows.push(...result.dadosInvalidos);
        if (result.chartData) allChartDataChunks.push(result.chartData);
    }

    const aggregatedCharts: ChartData[] = [];
    const chartMap = new Map<string, { type: 'bar' | 'pie'; data: Map<string, number> }>();
    allChartDataChunks.flat().forEach(chart => {
        if (!chartMap.has(chart.title)) chartMap.set(chart.title, { type: chart.type, data: new Map() });
        const existing = chartMap.get(chart.title)!;
        chart.data.forEach(p => existing.data.set(p.label, (existing.data.get(p.label) || 0) + p.value));
    });
    chartMap.forEach((v, title) => aggregatedCharts.push({ title, type: v.type, data: Array.from(v.data.entries()).map(([label, value]) => ({ label, value })) }));

    onProgress?.({ current: 1, total: 1, step: 'synthesize' });
    const finalResumo = await synthesizeSummaries(partialSummaries, userPrompt, filtersDescription, periodoAnalise);

    return { resumo: finalResumo, dadosInvalidos: allInvalidRows, chartData: aggregatedCharts };
};

export const correctUserPrompt = async (prompt: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: `Corrija a seguinte pergunta: "${prompt}"`,
            config: { systemInstruction: "Corrija a gramática e clareza, mantendo o significado. Retorne apenas o texto." },
        });
        return response.text?.trim() || prompt;
    } catch {
        return prompt;
    }
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { type AnalysisResultData, type SheetRow, type Filter } from './types';
import { analyzeSpreadsheetData, correctUserPrompt } from './services/geminiService';
import { generateSummaryImage } from './utils/imageGenerator';
import FileUpload from './components/FileUpload';
import DataTable from './components/DataTable';
import AnalysisResult from './components/AnalysisResult';
import FilterControls from './components/FilterControls';
import { LoadingSpinner, MicrophoneIcon, CloseIcon, InfoIcon } from './components/Icons';
import { useTheme } from './contexts/ThemeContext';

// Esta é uma declaração global para a biblioteca xlsx carregada da CDN
declare const XLSX: any;

// Para a API de Reconhecimento de Fala
declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

const App: React.FC = () => {
  const { theme } = useTheme();
  const [sheetData, setSheetData] = useState<SheetRow[]>([]);
  const [fileName, setFileName] = useState<string>('');
  const [analysisPrompt, setAnalysisPrompt] = useState<string>('Qual estúdio e qual equipe são os mais produtivos em termos de horas gravadas?');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [isCorrectingPrompt, setIsCorrectingPrompt] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [promptCorrectionError, setPromptCorrectionError] = useState<string | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResultData | null>(null);
  const [isListening, setIsListening] = useState<boolean>(false);
  const [analyzedRowCount, setAnalyzedRowCount] = useState<number | null>(null);
  const [summaryImage, setSummaryImage] = useState<string | null>(null);
  const [analysisProgress, setAnalysisProgress] = useState<{current: number, total: number, step: string} | null>(null);
  const recognitionRef = useRef<any>(null);
  const promptTextareaRef = useRef<HTMLTextAreaElement>(null);

  // Estado para os filtros
  const [availableColumns, setAvailableColumns] = useState<string[]>([]);
  const [columnValues, setColumnValues] = useState<Record<string, string[]>>({});
  const [activeFilters, setActiveFilters] = useState<Filter[]>([]);

  useEffect(() => {
    document.body.className = theme.classNames.background.main;
  }, [theme]);

  // Configura o Reconhecimento de Fala
  useEffect(() => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.lang = 'pt-BR';
      recognitionRef.current.interimResults = false;

      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
      recognitionRef.current.onerror = (event: any) => {
        console.error('Speech recognition error', event.error);
        setIsListening(false);
      };
      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setAnalysisPrompt(transcript);
      };
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      recognitionRef.current?.start();
    }
  };

  const filteredData = useMemo(() => {
    if (activeFilters.length === 0) {
      return sheetData;
    }
    return sheetData.filter(row => {
      return activeFilters.every(filter => {
        const cellValue = row[filter.column];

        if (typeof filter.value === 'object' && filter.value !== null) { // Filtro de intervalo de datas
          let dateFromCell: Date | null = null;
          if (cellValue instanceof Date && !isNaN(cellValue.getTime())) {
            dateFromCell = cellValue;
          } else if (typeof cellValue === 'string') {
            const parts = cellValue.split('/');
            if (parts.length === 3) {
              const year = parseInt(parts[2]);
              const fullYear = year < 100 ? 2000 + year : year;
              const d = new Date(fullYear, parseInt(parts[1]) - 1, parseInt(parts[0]));
              if (!isNaN(d.getTime())) dateFromCell = d;
            }
          } else if (typeof cellValue === 'number') { // Data serial do Excel
            const d = new Date(Math.round((cellValue - 25569) * 86400 * 1000));
            if (!isNaN(d.getTime())) dateFromCell = d;
          }

          if (!dateFromCell) return false;

          const cellDate = new Date(dateFromCell.getFullYear(), dateFromCell.getMonth(), dateFromCell.getDate());
          const { start, end } = filter.value as { start?: string; end?: string };

          let passesStart = true;
          if (start) {
            const startDate = new Date(start + 'T00:00:00');
            if (!isNaN(startDate.getTime())) passesStart = cellDate.getTime() >= startDate.getTime();
          }

          let passesEnd = true;
          if (end) {
            const endDate = new Date(end + 'T00:00:00');
            if (!isNaN(endDate.getTime())) passesEnd = cellDate.getTime() <= endDate.getTime();
          }

          return passesStart && passesEnd;
        }

        if (cellValue instanceof Date) {
          return cellValue.toLocaleDateString('pt-BR') === filter.value;
        }

        return String(cellValue ?? '').trim().toLowerCase() === String(filter.value).trim().toLowerCase();
      });
    });
  }, [sheetData, activeFilters]);

  const processWorkbook = (workbook: any, name: string) => {
    try {
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const data: SheetRow[] = XLSX.utils.sheet_to_json(worksheet, { raw: false, dateNF: 'dd/mm/yyyy' });

        if (data.length > 0) {
          const dataWithIndices = data.map((row, index) => ({
            ...row,
            __originalRowIndex: index + 2, // A linha 1 é o cabeçalho, os dados começam na linha 2
          }));

          const columns = Object.keys(data[0]);
          setAvailableColumns(columns);

          const uniqueValues: Record<string, Set<string>> = {};
          columns.forEach(col => {
            uniqueValues[col] = new Set();
          });

          data.forEach(row => {
            columns.forEach(col => {
                const value = row[col];
                if (value !== null && value !== undefined && String(value).trim() !== '') {
                   uniqueValues[col].add(String(value).trim());
                }
            });
          });

          const columnValuesMap: Record<string, string[]> = {};
          columns.forEach(col => {
            columnValuesMap[col] = Array.from(uniqueValues[col]).sort();
          });

          setColumnValues(columnValuesMap);
          setSheetData(dataWithIndices);
        } else {
            setError("A planilha está vazia ou em um formato não suportado.");
        }
        setFileName(name);
        setActiveFilters([]);
        setAnalysisResult(null);
        setError(null);
        setSummaryImage(null);
    } catch (err) {
        console.error("Error processing workbook: ", err);
        const errorMessage = err instanceof Error ? err.message : String(err);
        setError(`Ocorreu um erro ao processar a planilha: ${errorMessage}. Verifique se o arquivo está em um formato suportado e se a primeira linha contém os cabeçalhos das colunas.`);
        setSheetData([]);
    }
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const data = new Uint8Array(e.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: 'array', cellDates: true });
          processWorkbook(workbook, file.name);
        } catch (err) {
            console.error("Error processing file:", err);
            const errorMessage = err instanceof Error ? err.message : String(err);
            setError(`Erro ao processar o arquivo: ${errorMessage}. Verifique se é um arquivo de planilha válido.`);
        } finally {
            setIsLoading(false);
        }
      };
      reader.onerror = () => {
          setError("Não foi possível ler o arquivo selecionado.");
          setIsLoading(false);
      }
      reader.readAsArrayBuffer(file);
    }
  };

  const handleUrlSubmit = async (url: string, year?: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const sheetIdMatch = url.match(/\/d\/(.*?)\//);
      if (!sheetIdMatch) {
        throw new Error("URL da Planilha Google inválida. Não foi possível encontrar o ID.");
      }
      const sheetId = sheetIdMatch[1];
      const exportUrl = `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=xlsx`;

      const response = await fetch(exportUrl);
      if (!response.ok) {
        throw new Error(`Falha ao buscar a planilha. Status: ${response.status}`);
      }
      const arrayBuffer = await response.arrayBuffer();
      const data = new Uint8Array(arrayBuffer);
      const workbook = XLSX.read(data, { type: 'array', cellDates: true });
      const nameToSet = year ? `Registros ${year}` : (workbook.Props?.Title || `URL: ${sheetId.substring(0, 12)}...`);
      processWorkbook(workbook, nameToSet);

    } catch (err: any) {
      console.error(err);
      setError(`Erro ao carregar da URL: ${err.message}. Verifique se o link está correto e com permissão de 'Qualquer pessoa com o link'.`);
      setSheetData([]);
    } finally {
      setIsLoading(false);
    }
  };

  const addFilter = (filter: Omit<Filter, 'id'>) => {
    setActiveFilters(prev => [...prev, { ...filter, id: Date.now() }]);
  };

  const removeFilter = (filterId: number) => {
    setActiveFilters(prev => prev.filter(f => f.id !== filterId));
  };

  const handleCorrectPrompt = async () => {
    if (!analysisPrompt.trim()) return;
    setIsCorrectingPrompt(true);
    setPromptCorrectionError(null);
    try {
        const corrected = await correctUserPrompt(analysisPrompt);
        setAnalysisPrompt(corrected);
    } catch(e: any) {
        console.error("Failed to correct prompt", e.message);
        setPromptCorrectionError(e.message);
    } finally {
        setIsCorrectingPrompt(false);
        promptTextareaRef.current?.focus();
    }
  };

  const getAnalysisPeriod = (data: SheetRow[]): string => {
    if (data.length === 0) return "Período de análise não pôde ser determinado.";
    const dateColumn = Object.keys(data[0] || {}).find(key => key.toLowerCase().includes('data'));
    if (!dateColumn) return "Período de análise não pôde ser determinado.";

    const dates = data.map(row => {
        const cellValue = row[dateColumn];
        if (cellValue instanceof Date && !isNaN(cellValue.getTime())) return cellValue;
        if (typeof cellValue === 'string') {
            const parts = cellValue.split('/');
            if (parts.length === 3) {
                const year = parseInt(parts[2]);
                const fullYear = year < 100 ? 2000 + year : year;
                const d = new Date(fullYear, parseInt(parts[1]) - 1, parseInt(parts[0]));
                if (!isNaN(d.getTime())) return d;
            }
        }
        return null;
    }).filter((d): d is Date => d !== null);

    if (dates.length === 0) return "Período de análise não pôde ser determinado.";

    const minDate = new Date(Math.min(...dates.map(d => d.getTime())));
    const maxDate = new Date(Math.max(...dates.map(d => d.getTime())));

    const formatDate = (d: Date) => d.toLocaleDateString('pt-BR', {timeZone: 'UTC', day: '2-digit', month: '2-digit', year: '2-digit'});

    return `Período analisado: de ${formatDate(minDate)} a ${formatDate(maxDate)}`;
  }

  const handleAnalysis = async () => {
    if (filteredData.length === 0 || !analysisPrompt.trim()) {
      setError("Por favor, carregue uma planilha e faça uma pergunta para iniciar a análise.");
      return;
    }
    setIsLoading(true);
    setError(null);
    setAnalysisResult(null);
    setSummaryImage(null);
    setAnalyzedRowCount(null);
    setAnalysisProgress(null);

    try {
      const periodoAnalise = getAnalysisPeriod(filteredData);
      const result = await analyzeSpreadsheetData(
        filteredData, 
        analysisPrompt, 
        activeFilters, 
        periodoAnalise,
        setAnalysisProgress
      );
      setAnalysisResult(result);
      setAnalyzedRowCount(filteredData.length);

      const image = await generateSummaryImage(analysisPrompt, result.resumo, activeFilters, theme.hex);
      setSummaryImage(image);

    } catch (err: any) {
      setError(err.message || "Ocorreu um erro desconhecido durante a análise.");
    } finally {
      setIsLoading(false);
      setAnalysisProgress(null);
    }
  };

  return (
    <div className={`min-h-screen ${theme.classNames.text.base} p-4 sm:p-6 lg:p-8`}>
      <div className="max-w-7xl mx-auto space-y-8">
        <header className="flex justify-between items-center">
          <div>
            <h1 className="text-2xl sm:text-3xl font-bold text-slate-100">Analisador de Planilhas de Estúdio</h1>
            <p className={theme.classNames.text.muted}>Use IA para extrair insights dos registros de gravação.</p>
          </div>
        </header>

        <main className="space-y-6">
          <section className={`${theme.classNames.background.card} p-6 rounded-lg shadow-md ${theme.classNames.border} border`}>
            <h2 className="text-lg font-semibold text-slate-100 mb-1">Faça sua Pergunta</h2>
            {fileName ? (
              <p className={`${theme.classNames.text.muted} text-sm mb-4`}>
                Analisando dados do arquivo: <span className='font-bold text-amber-400'>{fileName}</span>
              </p>
            ) : (
              <p className={`${theme.classNames.text.muted} text-sm mb-4`}>
                Carregue uma planilha para começar a análise.
              </p>
            )}
            <div className="relative">
              <textarea
                ref={promptTextareaRef}
                value={analysisPrompt}
                onChange={(e) => {
                  setAnalysisPrompt(e.target.value);
                  if (promptCorrectionError) setPromptCorrectionError(null);
                }}
                placeholder="Ex: Qual programa teve mais cancelamentos? Qual equipe teve o melhor aproveitamento de horas no Estúdio A?"
                rows={3}
                disabled={isLoading || sheetData.length === 0}
                className={`w-full p-3 pr-28 ${theme.classNames.background.input} ${theme.classNames.text.input} ${theme.classNames.border} border rounded-md focus:outline-none ${theme.classNames.focusRing} ${theme.classNames.text.placeholder} transition-shadow disabled:opacity-50 resize-none`}
              />
              <div className="absolute top-1/2 right-3 transform -translate-y-1/2 flex items-center gap-2">
                {analysisPrompt && (
                  <button
                    onClick={() => setAnalysisPrompt('')}
                    disabled={isLoading}
                    className={`${theme.classNames.text.muted} hover:text-white p-1 rounded-full hover:bg-blue-800 transition-colors`}
                    aria-label="Limpar pergunta"
                  >
                    <CloseIcon className="w-4 h-4" />
                  </button>
                )}
                <button
                  onClick={toggleListening}
                  disabled={isLoading || !recognitionRef.current || sheetData.length === 0}
                  className={`p-2 rounded-full transition-colors ${isListening ? 'bg-red-500 text-white animate-pulse' : `${theme.classNames.text.muted} hover:bg-blue-800`}`}
                  aria-label={isListening ? 'Parar gravação' : 'Gravar pergunta'}
                >
                  <MicrophoneIcon className="w-5 h-5" />
                </button>
              </div>
            </div>
            {promptCorrectionError && <p className="text-sm text-red-400 mt-2 px-1">{promptCorrectionError}</p>}

            {sheetData.length > 0 && (
              <div className="mt-4 text-xs text-blue-200 bg-blue-950/50 p-3 rounded-lg flex items-start gap-2 border border-blue-800">
                <InfoIcon className="w-4 h-4 mt-0.5 flex-shrink-0 text-amber-400" />
                <div>
                  <strong className="font-semibold text-slate-100">Dica de Análise:</strong> Lembre-se que programas do tipo 'Cancelado' (C) possuem apenas horários reservados (res) e não realizados (rea). A IA já considera esta regra para identificar inconsistências.
                </div>
              </div>
            )}

            <div className="flex flex-col sm:flex-row gap-2 mt-4">
                <button
                    onClick={handleAnalysis}
                    disabled={isLoading || filteredData.length === 0}
                    className={`w-full sm:w-auto flex-grow ${theme.classNames.primary.bg} ${theme.classNames.primary.text} font-bold py-3 px-6 rounded-md ${theme.classNames.primary.hover} disabled:opacity-50 disabled:cursor-not-allowed transition duration-150 flex items-center justify-center gap-2`}
                >
                    {isLoading ? <LoadingSpinner className="w-5 h-5" /> : 'Analisar Dados'}
                </button>
                <button
                    onClick={handleCorrectPrompt}
                    disabled={isLoading || isCorrectingPrompt || !analysisPrompt || sheetData.length === 0}
                    className={`w-full sm:w-auto ${theme.classNames.secondaryButton.bg} ${theme.classNames.secondaryButton.text} font-semibold py-3 px-4 rounded-md ${theme.classNames.secondaryButton.hover} disabled:opacity-50 disabled:cursor-not-allowed transition duration-150 flex items-center justify-center gap-2`}
                >
                    {isCorrectingPrompt ? <LoadingSpinner className="w-5 h-5" /> : 'Corrigir Texto'}
                </button>
            </div>
          </section>

          <AnalysisResult 
            result={analysisResult} 
            isLoading={isLoading && sheetData.length > 0} 
            error={error} 
            analyzedRowCount={analyzedRowCount}
            summaryImage={summaryImage}
            sheetData={filteredData}
            fileName={fileName}
            activeFilters={activeFilters}
            analysisProgress={analysisProgress}
            analysisPrompt={analysisPrompt}
          />

          <section className={`${theme.classNames.background.card} p-6 rounded-lg shadow-md ${theme.classNames.border} border`}>
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-lg font-semibold text-slate-100">Filtros e Visualização dos Dados</h2>
              </div>
              {sheetData.length > 0 ? (
                <>
                  <p className={`${theme.classNames.text.muted} text-sm mb-4`}>
                    Refine os dados para a análise. A tabela abaixo mostra {filteredData.length.toLocaleString('pt-BR')} de {sheetData.length.toLocaleString('pt-BR')} linhas.
                  </p>
                  <FilterControls 
                    availableColumns={availableColumns}
                    columnValues={columnValues}
                    activeFilters={activeFilters}
                    onAddFilter={addFilter}
                    onRemoveFilter={removeFilter}
                    disabled={isLoading}
                  />
                  <div className="mt-4">
                    <DataTable data={filteredData.slice(0, 100)} />
                    {filteredData.length > 100 && (
                        <p className={`text-xs ${theme.classNames.text.muted} text-center mt-2`}>
                            Apenas as primeiras 100 linhas filtradas são exibidas na tabela.
                        </p>
                    )}
                  </div>
                </>
              ) : (
                <div className="text-center py-10">
                    <p className={`${theme.classNames.text.muted}`}>
                        Carregue uma planilha para visualizar e filtrar os dados.
                    </p>
                </div>
              )}
          </section>

          <section className={`${theme.classNames.background.card} p-6 rounded-lg shadow-md ${theme.classNames.border} border`}>
            <h2 className="text-lg font-semibold text-slate-100 mb-4">Importar / Carregar Arquivo</h2>
            <FileUpload 
              onFileChange={handleFileChange}
              onUrlSubmit={handleUrlSubmit}
              fileName={fileName}
              isLoading={isLoading}
            />
          </section>

        </main>

        <footer className={`text-center py-4 text-sm ${theme.classNames.text.muted}`}>
            <p>&copy; {new Date().getFullYear()} Analisador de Planilhas. Criado com a API Gemini.</p>
        </footer>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';
import type { AnalysisResultData, SheetRow, Filter, ChartData } from '../types';
import AnalysisAnimation from './AnalysisAnimation';
import { useTheme } from '../contexts/ThemeContext';
import { typeMapping } from '../types';
import { DownloadIcon } from './Icons';

// Declaração para a biblioteca Chart.js carregada globalmente via CDN
declare const Chart: any;

// --- Funções Auxiliares para Geração de Imagem ---

function wrapText(
    context: CanvasRenderingContext2D, 
    text: string, 
    x: number, 
    y: number, 
    maxWidth: number, 
    lineHeight: number
): number {
    const paragraphs = text.split('\n');
    let currentY = y;

    for (const paragraph of paragraphs) {
        const words = paragraph.split(' ');
        let line = '';

        for (let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = context.measureText(testLine);
            const testWidth = metrics.width;
            if (testWidth > maxWidth && n > 0) {
                context.fillText(line.trim(), x, currentY);
                line = words[n] + ' ';
                currentY += lineHeight;
            } else {
                line = testLine;
            }
        }
        context.fillText(line.trim(), x, currentY);
        currentY += lineHeight;
    }

    return currentY;
}

function formatFilters(filters: Filter[]): string {
    if (filters.length === 0) {
        return '';
    }

    return filters.map(filter => {
        let displayValue: string;
        if (typeof filter.value === 'object' && filter.value !== null) {
            const { start, end } = filter.value as { start?: string; end?: string };
            const formatDate = (dateStr?: string) => dateStr ? new Date(dateStr + 'T00:00:00').toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: '2-digit' }) : '...';
            if (start && end) {
                displayValue = `${formatDate(start)} - ${formatDate(end)}`;
            } else if (start) {
                displayValue = `a partir de ${formatDate(start)}`;
            } else if (end) {
                displayValue = `até ${formatDate(end)}`;
            } else {
                displayValue = 'Intervalo de data inválido';
            }
        } else {
            let tempDisplayValue = filter.value as string;
            if (filter.column.toLowerCase().includes('tipo') && typeof tempDisplayValue === 'string' && typeMapping[tempDisplayValue.toUpperCase()]) {
                tempDisplayValue = typeMapping[tempDisplayValue.toUpperCase()];
            }
            displayValue = tempDisplayValue;
        }
        return `• ${filter.column}: ${displayValue}`;
    }).join('\n');
}

// --- Componentes do Gráfico ---

interface ChartsProps {
  chartData: ChartData[];
  analysisPrompt: string;
  activeFilters: Filter[];
}

const ChartComponent: React.FC<{ chart: ChartData, analysisPrompt: string, activeFilters: Filter[] }> = ({ chart, analysisPrompt, activeFilters }) => {
    const { theme } = useTheme();
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const chartRef = useRef<any>(null);

    useEffect(() => {
        if (!canvasRef.current) return;

        const ctx = canvasRef.current.getContext('2d');
        if (!ctx) return;

        if (chartRef.current) {
            chartRef.current.destroy();
        }

        const labels = chart.data.map(d => d.label);
        const data = chart.data.map(d => d.value);

        const themeChartColors = theme.hex.chartColors;
        // Gera um array de cores mapeando cada label para uma cor do tema (ciclando se necessário)
        const backgroundColors = labels.map((_, i) => themeChartColors[i % themeChartColors.length]);

        const gridColor = 'rgba(255, 255, 255, 0.1)';
        const textColor = theme.hex.muted;

        const config: any = {
            type: chart.type,
            data: {
                labels,
                datasets: [{
                    label: chart.title,
                    data,
                    backgroundColor: backgroundColors,
                    borderColor: theme.hex.backgroundCard,
                    borderWidth: chart.type === 'pie' ? 2 : 1,
                }]
            },
            options: {
                responsive: true,
                maintainAspectRatio: true,
                aspectRatio: chart.type === 'pie' ? 1.5 : 2,
                plugins: {
                    legend: {
                        display: chart.type === 'pie' || chart.data.length > 1,
                        position: chart.type === 'pie' ? 'bottom' : 'top',
                        labels: {
                            color: textColor,
                            font: {
                                family: 'Inter, sans-serif'
                            }
                        }
                    },
                    title: {
                        display: true,
                        text: chart.title,
                        color: theme.hex.base,
                        font: {
                            size: 16,
                            family: 'Inter, sans-serif',
                            weight: '600'
                        }
                    },
                    tooltip: {
                        backgroundColor: theme.hex.backgroundMain,
                        titleColor: theme.hex.strong,
                        bodyColor: theme.hex.base
                    }
                },
            }
        };

        if (chart.type === 'bar') {
            config.options.indexAxis = 'y'; // Gráfico de barras horizontais para melhor legibilidade dos rótulos
            config.options.scales = {
                y: {
                    beginAtZero: true,
                    grid: { display: false },
                    ticks: { color: textColor }
                },
                x: {
                    grid: { color: gridColor },
                    ticks: { color: textColor }
                }
            }
        }

        chartRef.current = new Chart(ctx, config);

        return () => {
            if (chartRef.current) {
                chartRef.current.destroy();
            }
        };
    }, [chart, theme]);

    const handleDownload = async () => {
        if (!canvasRef.current) return;
        await document.fonts.ready;

        const originalCanvas = canvasRef.current;
        const { width, height } = originalCanvas;

        const padding = 20;
        const sectionSpacing = 15;
        const questionLineHeight = 22;
        const filterTitleLineHeight = 20;
        const filterLineHeight = 18;

        const tempCanvas = document.createElement('canvas');
        tempCanvas.width = width;
        tempCanvas.height = 10000;
        const tempCtx = tempCanvas.getContext('2d');
        if (!tempCtx) return;

        let textY = 0;

        tempCtx.font = `bold 18px Inter, sans-serif`;
        textY = wrapText(tempCtx, `Pergunta: ${analysisPrompt}`, 0, textY, width - padding * 2, questionLineHeight);
        textY += sectionSpacing;

        const filtersText = formatFilters(activeFilters);
        if (filtersText) {
            tempCtx.font = `bold 16px Inter, sans-serif`;
            textY = wrapText(tempCtx, 'Filtros Aplicados:', 0, textY, width - padding * 2, filterTitleLineHeight);
            textY += 5;
            tempCtx.font = `14px Inter, sans-serif`;
            textY = wrapText(tempCtx, filtersText, 0, textY, width - padding * 2, filterLineHeight);
        }

        const finalHeight = height + textY + padding;

        const finalCanvas = document.createElement('canvas');
        finalCanvas.width = width;
        finalCanvas.height = finalHeight;
        const finalCtx = finalCanvas.getContext('2d');
        if (!finalCtx) return;

        finalCtx.fillStyle = theme.hex.backgroundCard;
        finalCtx.fillRect(0, 0, width, finalHeight);
        finalCtx.drawImage(originalCanvas, 0, 0);

        let currentY = height + padding;
        finalCtx.textBaseline = 'top';

        finalCtx.font = `bold 18px Inter, sans-serif`;
        finalCtx.fillStyle = theme.hex.strong;
        currentY = wrapText(finalCtx, `Pergunta: ${analysisPrompt}`, padding, currentY, width - padding * 2, questionLineHeight);
